import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../characters';
import { Portrait } from '../portraits';
import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "臨時指揮區設在操場邊的軍綠色大帳篷裡。雨打在帳篷頂上，聲音密集而沉悶。帳篷裡擺了幾張摺疊桌，桌上攤著校園地圖、人員配置表、車輛調度紀錄。對講機的聲音此起彼伏。三個校安在整理名牌。一個技術人員蹲在角落修監視器線路。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔站在桌子中央，手裡拿著對講機，正在和一個穿深灰色西裝的中年人說話。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "金屬細框眼鏡。頭髮梳得很整齊。胸前別著校徽。手指在桌面上敲了兩下，像在壓抑什麼。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)林主任也在。他管行政、場地、門禁。和上一輪一樣的時間、一樣的位置。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "——對，鐘樓那邊的巡邏要加密。今天媒體都在，不能讓學生亂跑上去。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.ShaoQiming_Base },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "邵警官，百年校慶的流程我比你熟。鐘樓本來就不開放，不需要額外——", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.LinZhuren_Base },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "今天雨大，電路出問題誰負責？", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.ShaoQiming_Base },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "⋯⋯", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.LinZhuren_Base },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "我先看過維修紀錄再說。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.ShaoQiming_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔的語氣很平。不重，不急。但每一句話都像釘子一樣精準地落在對方無法反駁的位置。林主任嘴唇動了動，最終沒有再開口。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他們在說鐘樓。我還沒開口，他們就在說鐘樓。因為鐘樓是今天安全流程的一部分。正常。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔的視線掃過帳篷入口，看見了顧言。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "小顧？", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.ShaoQiming_Concerned },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他放下對講機，走過來。步伐穩。笑容溫和。白牙。眼角有笑紋。和每一輪一樣的邵叔。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "臉色這麼差？昨晚沒睡？", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.ShaoQiming_Concerned },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第一輪，他問我吃飯了沒。第二輪，他問我臉色怎麼這麼白。這一輪，他問我昨晚沒睡。每一次，他的第一句話都是關心。溫暖的。耐心的。像父親一樣的。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但這一輪，我不會因為溫暖就放心。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "有人傳訊息給我。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說得很快，很平。沒有鋪墊。沒有「邵叔你先聽我說」。直接切入。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "什麼訊息？", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.ShaoQiming_Concerned },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "不是普通惡作劇。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把手機從口袋裡掏出來。螢幕解鎖。訊息頁面。那條匿名訊息還在那裡。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)手指位置。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把手機遞過去，但拇指精準地蓋在螢幕最下方。最後一行被完全遮住。邵叔看到的只有：", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "今晚 22:22，鐘樓會停電。不要上去⋯⋯", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "**旁白**後半段被拇指壓住了。不要把相機交給任何大人——邵叔看不見。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第一輪，我把整條訊息交給他。他看到了全部。他知道相機、鐘樓、大人、22:22。這一輪，我只讓他看到鐘樓和時間。相機——我要從我的嘴裡說出來。我要看他聽到這個詞時的眼睛。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "⋯⋯", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.ShaoQiming_Concerned },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔看著螢幕。眉頭微微皺起。不深。很淺。像在看一道不太難但不確定該怎麼回答的數學題。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "今天人多，有人拿校慶嚇你也不是不可能。但鐘樓牽涉電路，我會讓人查。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.ShaoQiming_Concerned },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)反應很快。沒有否定我。沒有搶手機。沒有驚慌。平穩的。專業的。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)現在。下一張牌。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "訊息還提到相機。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "四個字。他說得很輕。不刻意。不加重語氣。像在補充一個不太重要的細節。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔的反應——", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "停頓。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "半秒。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "很短。短到如果不盯著他的臉，根本不會注意到。但他確實停了。不是那種「思考怎麼回應」的停頓。是那種——聽到了一個不該出現在這裡的詞。像一台機器在運轉時突然被一顆小石子卡了一下齒輪。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯停了。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "什麼相機？", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.ShaoQiming_Concerned },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他問「什麼相機」。語氣沒變。表情沒變。但剛才那半秒——我看到了。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言沒有回答。他沒有把手機翻過來。拇指仍然壓在最後一行上。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "我剛才在車輛表上看到，傍晚有一輛直播備份器材車要出校。備援路線是後山維修路。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說得很快。像是在整理自己的思路，不像是刻意在告訴邵叔什麼。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "訊息提到相機，鐘樓又會停電，我覺得有人可能會利用校慶器材做什麼。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有說「有人會攔車」。他沒有說「後山會出事」。他只說「可能會利用器材」。這是一個學生看到車輛表、看到訊息之後能做出的合理聯想。不超越。不預知。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔的反應分三層。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第一層——聽到「鐘樓」時。他的肩膀微微繃緊了一下。警覺。但這種警覺可以解釋為專業反應：鐘樓停電，電路問題，安全隱患。合理的。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第二層——聽到「相機」時。那半秒的停頓。已經記下了。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第三層——聽到「後山維修路」時。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的第一眼，不是看顧言。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看向了林主任的方向。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯林主任。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他聽到「後山維修路」的第一反應，不是看我，不是看車輛表，不是問我怎麼知道的。他看的是林主任。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)為什麼？後山維修路和林主任有什麼關係？車輛調度的負責欄寫的是行政組協調。林主任管行政。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)還是——他在確認林主任有沒有聽到？", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔收回視線，切回專業模式。動作很快，像一個人把一扇剛打開的窗重新關上。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "你做得對。這種事不能自己查。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.ShaoQiming_Serious },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這句話說得溫和。肯定。像一個大人在誇一個做了正確決定的孩子。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)你做得對。這種事不能自己查。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這句話——我應該覺得安心嗎？", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔轉身，語氣變了。不再是溫和的長輩，而是指揮官。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "老李，叫校安確認鐘樓有沒有臨時維修。如果有，我要知道是誰批准的。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.ShaoQiming_Serious },
    { characterId: CharacterId.SecurityGuard, character: "校安", dialogue: "收到。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "林主任，鐘樓門禁和電力檢修紀錄，麻煩提供一下。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.ShaoQiming_Serious },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "⋯⋯今天百年校慶，流程本來就——", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.LinZhuren_Base },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "出事你負責？", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.ShaoQiming_Serious },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任的嘴唇抿成一條線。金屬細框眼鏡後面的眼睛閃了一下——不是憤怒，是恐懼。但這個表情只持續了不到一秒，就被他慣常的官腔面具蓋住了。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "⋯⋯我讓人調。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.LinZhuren_Base },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "還有，傍晚那輛直播備份器材車，先不要出校。保全那邊確認一下。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.ShaoQiming_Serious },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔回過頭，看著顧言。他的眼神溫和下來，像是在說「放心，交給我」。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "你今天不要一個人亂跑。有什麼動態我通知你。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.ShaoQiming_Concerned },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個字。他的標準回答。但這一次，這個「嗯」字的重量不一樣了。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)三件事。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第一，他聽到「鐘樓」時是警覺。這個可以解釋為專業。但他的警覺太自然了，自然到像排練過。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第二，他聽到「相機」時停了半秒。不是思考。是觸發。這個詞對他有意義。不是「學生的惡作劇裡提到相機」那種意義。是更深的那種。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第三，他聽到「後山維修路」時，第一眼看的是林主任。不是看我。不是問我從哪裡知道的。他在確認林主任。要麼是確認林主任知不知道這條路線，要麼是——在確認林主任有沒有在聽。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "帳篷外的雨更大了。對講機裡的聲音變得斷斷續續。校安拿著紙筆在記錄。技術人員繼續修線路。林主任站在桌邊，手指在桌面上無意識地敲著，節奏越來越快。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)邵叔現在的每一個動作都符合「可靠大人」的定義。他沒有搶我手機。他沒有追問訊息來源。他沒有質疑我為什麼知道車輛表。他做的事情全都對。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)太對了。對到讓人不安。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但他已經動了。他開始封鐘樓。他開始查器材車。他開始壓林主任。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)流程啟動了。接下來會發生什麼——我要一直看著。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "小顧，你先待在附近。別跑遠。等我處理完這些再找你。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.ShaoQiming_Concerned },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "好。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔拍了拍他的肩膀。力道不重。手掌的溫度透過校服傳過來。那隻手很大、很穩，像一塊可靠的盾牌。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)那隻手。和第一輪一樣的手。和第二輪——我不確定。第二輪我一直在躲他。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第一輪，他拍過我的肩。然後我去鐘樓。我死了。第二輪，我避開了他的手。我搭了校務車。我也死了。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這一輪，他又拍了我的肩。這隻手——是保護的手，還是按住我的手？", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔轉身，繼續處理帳篷裡的流程。他的背影寬而穩，深藍色制服的肩線在帳篷的昏黃光線下顯得格外可靠。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言站在帳篷入口，看著那個背影，看著他拿起對講機、指派校安、壓住林主任、讓整個校園安全系統按照他的意志轉動。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他真的能讓所有路線停止。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)鐘樓。校務車。監控。門禁。人員調度。他一個人就能碰所有這些。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這是他的能力。是他的權限。也是——如果他是那把刀的話——他的武器。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他退後一步，離開帳篷入口。雨落在他的臉上、肩膀上、手背上。他沒有擦。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)09:05。流程已經動了。接下來，我只需要做一件事。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)看。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)看他把我的線索送到哪裡。看他把我送到哪裡。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果他送我去的是安全的地方——那他是保護傘。如果他送我去的是另一個死角——", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)那我就知道答案了。雖然那個答案可能來不及用了。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨繼續下。帳篷裡的對講機聲繼續響。百年校慶的早晨繼續按照它的劇本推進。而顧言站在雨裡，像一個已經把棋子放上棋盤、正在等對手落子的人。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他知道：接下來的每一分鐘，都是測試。而測試的代價，可能是他的第三條命。", background: Background.Chapter_3_Ch3_Act4_S0 },
];
